fullScript:
#!/bin/bash
set -euo pipefail

# Node.js Memory Leak Detection Script

APP_FILE="${1:-app.js}"
INTERVAL="${2:-30}"

echo "==> Starting memory monitoring for ${APP_FILE}..."
echo "    Sampling every ${INTERVAL} seconds"
echo ""

# Create monitoring wrapper
cat > /tmp/mem-monitor.js <<'MONITOR'
const v8 = require('v8');
const path = require('path');

// Memory logging
const baseline = process.memoryUsage().heapUsed;
let samples = [];

setInterval(() => {
  const mem = process.memoryUsage();
  const heapMB = Math.round(mem.heapUsed / 1024 / 1024);
  const rssMB = Math.round(mem.rss / 1024 / 1024);
  const growthMB = Math.round((mem.heapUsed - baseline) / 1024 / 1024);

  samples.push(heapMB);

  const trend = samples.length > 5
    ? (samples[samples.length - 1] > samples[0] ? 'GROWING' : 'STABLE')
    : 'SAMPLING';

  console.log(`[MEM] heap=${heapMB}MB rss=${rssMB}MB growth=${growthMB >= 0 ? '+' : ''}${growthMB}MB trend=${trend}`);

  if (trend === 'GROWING' && samples.length > 10) {
    console.log('[MEM] WARNING: Memory appears to be leaking. Consider taking a heap snapshot.');
  }
}, parseInt(process.env.MONITOR_INTERVAL || '30') * 1000);

// Snapshot on SIGUSR2
process.on('SIGUSR2', () => {
  const file = v8.writeHeapSnapshot();
  console.log('[MEM] Heap snapshot written to:', file);
});

console.log('[MEM] Memory monitor active. PID:', process.pid);
console.log('[MEM] Send SIGUSR2 to take heap snapshot');
MONITOR

echo "==> Running with memory monitor..."
MONITOR_INTERVAL=${INTERVAL} node --inspect --max-old-space-size=512 -r /tmp/mem-monitor.js "${APP_FILE}"
